import{_ as t,o as a,c as s,a0 as n}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Event & Instance Tests","description":"","frontmatter":{},"headers":[],"relativePath":"testing/event-tests.md","filePath":"testing/event-tests.md"}'),l={name:"testing/event-tests.md"};function i(r,e,o,c,d,h){return a(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="event-instance-tests" tabindex="-1">Event &amp; Instance Tests <a class="header-anchor" href="#event-instance-tests" aria-label="Permalink to &quot;Event &amp; Instance Tests&quot;">​</a></h1><p>Use this guide to confirm event-type behavior, default-event protection, instance locking, and stage handling.</p><h2 id="test-1-default-event-types" tabindex="-1">Test 1. Default event types <a class="header-anchor" href="#test-1-default-event-types" aria-label="Permalink to &quot;Test 1. Default event types&quot;">​</a></h2><ol><li>Open <a href="./../events/bear-trap.html">Bear Trap</a>. Expected result: it behaves as a score-based single-session event.</li><li>Open <a href="./../events/viking-vengeance.html">Viking Vengeance</a>. Expected result: it behaves as a score-based single-session event.</li><li>Open <a href="./../events/alliance-mobilization.html">Alliance Mobilization</a>. Expected result: it behaves as a cumulative score event, not as staged daily scores.</li><li>Open <a href="./../events/alliance-brawl.html">Alliance Brawl</a>. Expected result: it behaves as a multi-stage event where stage choice matters.</li><li>Open <a href="./../events/kingdom-of-power.html">Kingdom of Power</a>. Expected result: it behaves as a kingdom-wide multi-stage event.</li><li>Open <a href="./../events/strongest-governor.html">Strongest Governor</a>. Expected result: it behaves as a multi-stage individual-ranking event.</li><li>Open <a href="./../events/sanctuary-battle.html">Sanctuary Battle</a>. Expected result: it is treated as participation and control oriented, not as a normal score-first event.</li></ol><h2 id="test-2-default-event-delete-protection" tabindex="-1">Test 2. Default-event delete protection <a class="header-anchor" href="#test-2-default-event-delete-protection" aria-label="Permalink to &quot;Test 2. Default-event delete protection&quot;">​</a></h2><ol><li>Try to delete the default Bear Trap template. Expected result: the action is blocked with <strong>&quot;Default events can be edited, but they cannot be deleted.&quot;</strong></li></ol><h2 id="test-3-lock-and-unlock-cycle" tabindex="-1">Test 3. Lock and unlock cycle <a class="header-anchor" href="#test-3-lock-and-unlock-cycle" aria-label="Permalink to &quot;Test 3. Lock and unlock cycle&quot;">​</a></h2><ol><li>Create an event instance. Expected result: the instance is writable.</li><li>End it and advance the test clock or data so it is more than 3 days past end. Expected result: the instance becomes locked.</li><li>Attempt a write. Expected result: the write is blocked with <strong>&quot;This event instance is locked. Request unlock or ask a leader to unlock it.&quot;</strong></li><li>Submit an unlock request. Expected result: the request is created.</li><li>Approve the unlock as an authorized reviewer. Expected result: the instance becomes writable again.</li><li>Retry the write. Expected result: the write succeeds.</li></ol><h2 id="test-4-alliance-brawl-stage-import" tabindex="-1">Test 4. Alliance Brawl stage import <a class="header-anchor" href="#test-4-alliance-brawl-stage-import" aria-label="Permalink to &quot;Test 4. Alliance Brawl stage import&quot;">​</a></h2><ol><li>Open an Alliance Brawl instance or import context. Expected result: stage-aware options are available.</li><li>Choose <strong>Stage Data</strong> and <strong>Stage 1</strong> for a Day 1 screenshot. Expected result: the selected stage is stored with the import context.</li><li>Complete the review and accept flow. Expected result: the saved result is attached to the correct stage instead of being treated as an unspecified total.</li></ol>',10)])])}const v=t(l,[["render",i]]);export{p as __pageData,v as default};
